import React, { useState } from 'react';
import { View, Text, Button } from 'react-native';
import axios from 'axios';

const NetworkingModule = () => {
  const [responseData, setResponseData] = useState(null);

  const fetchData = async () => {
    try {
      const response = await axios.get('https://api.example.com/data', {
        headers: {
          'Content-Type': 'application/json',
          Accept: 'application/json'
        }
      });
      setResponseData(response.data);
    } catch (error) {
      console.log(error);
    }
  };

  const fetchLocalIoTDevice = async () => {
    try {
      const response = await axios.get('http://192.168.x.x/data', {
        headers: {
          'Content-Type': 'application/json',
          Accept: 'application/json'
        }
      });
      setResponseData(response.data);
    } catch (error) {
      console.log(error);
    }
  };

  return (
    <View>
      <Button title="Fetch Data" onPress={fetchData} />
      <Button title="Fetch Local IoT Device" onPress={fetchLocalIoTDevice} />
      {responseData && <Text>{JSON.stringify(responseData)}</Text>}
    </View>
  );
};

export default NetworkingModule;